    private func requestPushNotificationPermission() {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { [weak self] granted, error in
            DispatchQueue.main.async {
                if granted {
                    UIApplication.shared.registerForRemoteNotifications()
                }
                self?.sendJavaScriptCallback("window.NativeBridge.onPushPermissionResult", data: [
                    "granted": granted,
                    "error": error?.localizedDescription ?? ""
                ])
            }
        }
    }
    
    private func getPushToken() {
        // Token is typically stored when received in AppDelegate
        let token = UserDefaults.standard.string(forKey: "pushNotificationToken") ?? ""
        sendJavaScriptCallback("window.NativeBridge.onPushTokenReceived", data: [
            "token": token
        ])
    }
    
    private func checkPushPermission() {
        UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
            let status: String
            switch settings.authorizationStatus {
            case .authorized: status = "authorized"
            case .denied: status = "denied"
            case .notDetermined: status = "notDetermined"
            case .provisional: status = "provisional"
            case .ephemeral: status = "ephemeral"
            @unknown default: status = "unknown"
            }
            self?.sendJavaScriptCallback("window.NativeBridge.onPushPermissionStatus", data: [
                "status": status
            ])
        }
    }
    
